     1→/**
     2→ * InfiniteCanvas - Professional-grade pan/zoom canvas
     3→ *
     4→ * Features:
     5→ * - Pan with mouse drag (bounded to world limits)
     6→ * - Zoom with scroll wheel (centers on cursor position)
     7→ * - Initial view shows top-left of data (X=0, Y=0)
     8→ * - Sidebar sync via onViewportChange callback
     9→ *
    10→ * Coordinate System:
    11→ * - X: 0 = first day, positive = future (right)
    12→ * - Y: 0 = first train (TRAIN-001), negative = more trains (down)
    13→ *
    14→ * References:
    15→ * - D3.js zoom: https://d3js.org/d3-zoom
    16→ * - Three.js OrthographicCamera: https://threejs.org/docs/api/en/cameras/OrthographicCamera.html
    17→ * - pixi-viewport: https://github.com/pixijs-userland/pixi-viewport
    18→ */
    19→
    20→import { Canvas, useThree } from '@react-three/fiber';
    21→import { useState, useCallback, useMemo, useEffect, useRef } from 'react';
    22→import { MesoLayer } from './layers/MesoLayer';
    23→import { MacroLayer } from './layers/MacroLayer';
    24→import { MicroLayer } from './layers/MicroLayer';
    25→import { getRenderData } from '../data/generator';
    26→import type { LODLevel, WorldBounds } from '../data/types';
    27→import { DEFAULT_VIEW_CONFIG, calculateWorldBounds } from '../data/types';
    28→import { PerfMonitor, usePerfToggle, usePerfEvent } from '../components/PerfMonitor';
    29→import type { PerfEvent } from '../components/PerfMonitor';
    30→
    31→// ─────────────────────────────────────────────────────────────
    32→// EXPORTED TYPES
    33→// ─────────────────────────────────────────────────────────────
    34→
    35→/**
    36→ * Viewport information passed to parent component
    37→ */
    38→export interface ViewportInfo {
    39→  /** Y coordinate of the TOP of the viewport in world space */
    40→  topY: number;
    41→  /** Left edge of the viewport in world X coordinates */
    42→  leftX: number;
    43→  /** Right edge of the viewport in world X coordinates */
    44→  rightX: number;
    45→}
    46→
    47→/**
    48→ * Viewport bounds in world coordinates
    49→ * Used for frustum culling - only render tasks within these bounds
    50→ */
    51→export interface ViewportBounds {
    52→  minX: number;
    53→  maxX: number;
    54→  minY: number;
    55→  maxY: number;
    56→}
    57→
    58→// ─────────────────────────────────────────────────────────────
    59→// LOD CONFIGURATION
    60→// ─────────────────────────────────────────────────────────────
    61→
    62→/**
    63→ * LOD Transition Configuration
    64→ *
    65→ * Defines blend zones around LOD thresholds for smooth transitions.
    66→ * During blend zones, both adjacent layers render with interpolated opacity.
    67→ */
    68→const LOD_THRESHOLDS = {
    69→  macroToMeso: 0.5,  // Below 0.5 = MACRO
    70→  mesoToMicro: 2.0,  // Above 2.0 = MICRO
    71→};
    72→
    73→// Size of blend zone around each threshold (±this value)
    74→const BLEND_ZONE_SIZE = 0.15;
    75→
    76→/**
    77→ * Calculate layer opacities for smooth LOD transitions
    78→ *
    79→ * Returns opacity values for each layer (0-1).
    80→ * During blend zones, adjacent layers overlap with interpolated opacity.
    81→ */
    82→function calculateLayerOpacities(zoom: number): {
    83→  macro: number;
    84→  meso: number;
    85→  micro: number;
    86→} {
    87→  const { macroToMeso, mesoToMicro } = LOD_THRESHOLDS;
    88→
    89→  // Define blend zone boundaries
    90→  const macroEnd = macroToMeso - BLEND_ZONE_SIZE; // 0.35
    91→  const mesoStart = macroToMeso + BLEND_ZONE_SIZE; // 0.65
    92→  const mesoEnd = mesoToMicro - BLEND_ZONE_SIZE; // 1.85
    93→  const microStart = mesoToMicro + BLEND_ZONE_SIZE; // 2.15
    94→
    95→  let macro = 0;
    96→  let meso = 0;
    97→  let micro = 0;
    98→
    99→  // Calculate MACRO opacity
   100→  if (zoom <= macroEnd) {
   101→    macro = 1;
   102→  } else if (zoom < mesoStart) {
   103→    // Blend zone MACRO → MESO
   104→    const t = (zoom - macroEnd) / (mesoStart - macroEnd);
   105→    macro = 1 - t;
   106→  }
   107→
   108→  // Calculate MESO opacity
   109→  if (zoom < macroEnd) {
   110→    meso = 0;
   111→  } else if (zoom < mesoStart) {
   112→    // Blend zone MACRO → MESO
   113→    const t = (zoom - macroEnd) / (mesoStart - macroEnd);
   114→    meso = t;
   115→  } else if (zoom <= mesoEnd) {
   116→    meso = 1;
   117→  } else if (zoom < microStart) {
   118→    // Blend zone MESO → MICRO
   119→    const t = (zoom - mesoEnd) / (microStart - mesoEnd);
   120→    meso = 1 - t;
   121→  }
   122→
   123→  // Calculate MICRO opacity
